                processSharedText(sharedText)
            }
            "image/*" -> {
                val sharedImageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                processSharedImage(sharedImageUri)
            }
        }
    }

    private fun handleSendMultipleIntent(intent: Intent) {
        val sharedUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
        if (sharedUris != null) {
            for (uri in sharedUris) {
                when (intent.type) {
                    "image/*" -> processSharedImage(uri)
                }
            }
        }
    }

